#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, X, P;
        scanf("%d %d %d", &N, &X, &P);
        int score = 4 * X - N;
        if (score >= P) {
            printf("PASS\n");
        } else {
            printf("FAIL\n");
        }
    }
    return 0;
}

